# 栈与队列的经典应用：括号匹配
from collections import deque

def is_valid(s: str) -> bool:
    stack = []
    pairs = {')': '(', ']': '[', '}': '{'}

    for ch in s:
        if ch in '([{':
            stack.append(ch)          # 入栈
        elif ch in ')]}':
            if not stack or stack[-1] != pairs[ch]:
                return False           # 不匹配或栈空
            stack.pop()                # 匹配成功，出栈

    return len(stack) == 0

# 队列实现：滑动窗口最大值（简化版）
def max_in_windows(nums, k):
    from collections import deque
    q = deque()  # 存储索引，保持单调递减
    result = []

    for i, num in enumerate(nums):
        # 移除窗口外的元素
        if q and q[0] <= i - k:
            q.popleft()
        # 移除所有小于当前值的元素
        while q and nums[q[-1]] <= num:
            q.pop()

        q.append(i)
        if i >= k - 1:
            result.append(nums[q[0]])  # 队首即最大值
    return result

print(is_valid("{[()]}"))        # True
print(max_in_windows([1,3,-1,-3,5,3], 3))  # [3, 3, 5, 5]

# 双链表实现：支持 O(1) 删除已知节点
class DListNode:
    def __init__(self, val=0):
        self.val = val
        self.prev = None
        self.next = None

class DoublyLinkedList:
    def __init__(self):
        self.head = DListNode()  # 哨兵节点
        self.tail = DListNode()
        self.head.next = self.tail
        self.tail.prev = self.head

    def _add_after(self, prev_node, val):
        """在 prev_node 后插入新节点"""
        new_node = DListNode(val)
        new_node.prev = prev_node
        new_node.next = prev_node.next
        prev_node.next.prev = new_node
        prev_node.next = new_node
        return new_node

    def remove(self, node):
        """O(1) 删除已知节点（需保证节点存在）"""
        node.prev.next = node.next
        node.next.prev = node.prev
        # 可选：断开指针，帮助垃圾回收
        node.prev = node.next = None

# 应用：LRU 缓存的核心数据结构
from collections import OrderedDict

class LRUCache:
    def __init__(self, capacity: int):
        self.cache = OrderedDict()
        self.capacity = capacity

    def get(self, key: int) -> int:
        if key not in self.cache:
            return -1
        self.cache.move_to_end(key)  # 标记为最近使用
        return self.cache[key]

    def put(self, key: int, value: int) -> None:
        if key in self.cache:
            self.cache.move_to_end(key)
        self.cache[key] = value
        if len(self.cache) > self.capacity:
            self.cache.popitem(last=False)  # 淘汰最久未使用
